    navBtn: (active) => ({ background: active ? "#fff2e7" : "#fff", border: "1px solid rgba(226,232,240,0.9)", padding: "9px 14px", borderRadius: 999, fontSize: 13, cursor: "pointer", color: active ? "#c2410c" : "#475569", fontWeight: active ? 700 : 600, boxShadow: active ? "0 14px 30px rgba(249,115,22,0.14)" : "0 10px 20px rgba(15,23,42,0.04)" }),
    postBtn: { background: "#f97316", color: "#fff", border: "none", borderRadius: 999, padding: "10px 18px", fontSize: 13, fontWeight: 800, cursor: "pointer", boxShadow: "0 18px 30px rgba(249,115,22,0.24)" },
    statusBadge: { padding: "6px 12px", borderRadius: 999, fontSize: 11, background: online ? "#ffedd5" : "#fee2e2", color: online ? "#c2410c" : "#b91c1c", fontWeight: 700 },
    hero: { background: "linear-gradient(135deg, #ff7a2d 0%, #fb923c 100%)", padding: "2.3rem 1.2rem 1.6rem", textAlign: "center", borderRadius: 32, margin: "1rem", boxShadow: "0 30px 80px rgba(251,146,60,0.22)" },
    h1: { fontSize: 30, fontWeight: 900, color: "#fff", marginBottom: 10, letterSpacing: 0.5 },
    sub: { color: "rgba(255,255,255,0.92)", fontSize: 15, marginBottom: "1.2rem" },
